sp_widget.client_script:
api.controller = function() {
    var c = this;
    c.showForm = false;
    c.submitting = false;
    c.newCollege = {};
    c.filterStatus = 'all';

    c.toggleForm = function() {
        c.showForm = !c.showForm;
        if (c.showForm) {
            c.newCollege = {};
            c.data.successMsg = '';
            c.data.errorMsg = '';
        }
    };

    c.createCollege = function() {
        if (c.submitting) return;
        if (!c.newCollege.name || !c.newCollege.code) {
            c.data.errorMsg = 'Please provide at least a Name and Code.';
            return;
        }
        c.submitting = true;
        c.data.successMsg = '';
        c.data.errorMsg = '';

        c.server.get({
            action: 'create_college',
            name: c.newCollege.name,
            code: c.newCollege.code,
            email_domain: c.newCollege.email_domain || '',
            website: c.newCollege.website || '',
            address: c.newCollege.address || ''
        }).then(function(r) {
            c.data = r.data;
            c.submitting = false;
            if (r.data.successMsg) {
                c.showForm = false;
                c.newCollege = {};
            }
        }, function() {
            c.data.errorMsg = 'Network error. Please try again.';
            c.submitting = false;
        });
    };

    c.verifyCollege = function(college) {
        if (c.submitting) return;
        c.submitting = true;
        c.data.successMsg = '';
        c.data.errorMsg = '';

        c.server.get({
            action: 'verify',
            college_id: college.sys_id
        }).then(function(r) {
            c.data = r.data;
            c.submitting = false;
        }, function() {
            c.data.errorMsg = 'Network error. Please try again.';
            c.submitting = false;
        });
    };

    c.suspendCollege = function(college) {
        if (c.submitting) return;
        c.submitting = true;
        c.data.successMsg = '';
        c.data.errorMsg = '';

        c.server.get({
            action: 'suspend',
            college_id: college.sys_id
        }).then(function(r) {
            c.data = r.data;
            c.submitting = false;
        }, function() {
            c.data.errorMsg = 'Network error. Please try again.';
            c.submitting = false;
        });
    };

    c.rejectCollege = function(college) {
        if (c.submitting) return;
        c.submitting = true;
        c.data.successMsg = '';
        c.data.errorMsg = '';

        c.server.get({
            action: 'reject',
            college_id: college.sys_id
        }).then(function(r) {
            c.data = r.data;
            c.submitting = false;
        }, function() {
            c.data.errorMsg = 'Network error. Please try again.';
            c.submitting = false;
        });
    };

    c.applyFilter = function() {
        if (c.submitting) return;
        c.submitting = true;
        c.data.successMsg = '';
        c.data.errorMsg = '';

        c.server.get({
            action: 'filter',
            filter_status: c.filterStatus
        }).then(function(r) {
            c.data = r.data;
            c.submitting = false;
        }, function() {
            c.data.errorMsg = 'Network error. Please try again.';
            c.submitting = false;
        });
    };
};

sp_widget.css:
.sp-manage-colleges .sp-panel {
    border: 1px solid $border-tertiary;
    box-shadow: 0 1px 4px rgba($text-color, 0.07);
}
.sp-manage-colleges .sp-panel .panel-heading {
    background: $background-secondary;
    border-bottom: 1px solid $border-tertiary;
    padding: 12px 15px;
}
.sp-manage-colleges .sp-panel .panel-title {
    font-size: 16px;
    font-weight: 600;
    color: $text-color;
    margin: 0;
    line-height: 30px;
}
.sp-manage-colleges .header-controls {
    display: inline-flex;
    align-items: center;
    gap: 8px;
}
.sp-manage-colleges .filter-label {
    margin-right: 4px;
    font-weight: 500;
    color: $text-muted;
}

/* Create Form */
.sp-manage-colleges .create-form {
    background: $state-info-bg;
    border-bottom: 1px solid $border-tertiary;
}
.sp-manage-colleges .create-form h5 {
    font-weight: 600;
    color: $text-color;
    margin-top: 0;
    margin-bottom: 16px;
}
.sp-manage-colleges .create-form .form-group label {
    font-weight: 500;
    color: $text-color;
}
.sp-manage-colleges .form-actions {
    margin-top: 12px;
    display: flex;
    gap: 8px;
}

/* Table */
.sp-manage-colleges .sp-panel .table th {
    color: $text-muted;
    font-weight: 600;
    font-size: 12px;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    border-bottom: 2px solid $border-tertiary;
}
.sp-manage-colleges .sp-panel .table td {
    vertical-align: middle;
    color: $text-color;
}
.sp-manage-colleges .action-na {
    font-size: 12px;
}

/* Empty State */
.sp-manage-colleges .empty-state {
    padding: 40px 20px;
}
.sp-manage-colleges .empty-icon {
    font-size: 48px;
    color: $text-muted;
    display: block;
    margin-bottom: 12px;
}

sp_widget.script:
(function() {
    data.colleges = [];
    data.successMsg = '';
    data.errorMsg = '';
    data.message = '';

    try {
        // Handle create college action
        if (input && input.action === 'create_college') {
            var newCollege = new GlideRecord('x_2097092_linq_college');
            newCollege.initialize();
            newCollege.setValue('name', input.name || '');
            newCollege.setValue('code', input.code || '');
            newCollege.setValue('email_domain', input.email_domain || '');
            newCollege.setValue('website', input.website || '');
            newCollege.setValue('address', input.address || '');
            newCollege.setValue('status', 'pending');

            var newId = newCollege.insert();
            if (newId) {
                data.successMsg = 'College created successfully!';
            } else {
                data.errorMsg = 'Failed to create college. Please try again.';
            }
        }

        // Handle verify action
        if (input && input.action === 'verify') {
            var verifyGr = new GlideRecord('x_2097092_linq_college');
            verifyGr.setLimit(1);
            if (verifyGr.get(input.college_id)) {
                verifyGr.setValue('status', 'verified');
                verifyGr.setValue('verified_on', new GlideDateTime());
                verifyGr.update();
                data.successMsg = 'College verified successfully!';
            } else {
                data.errorMsg = 'College not found.';
            }
        }

        // Handle suspend action
        if (input && input.action === 'suspend') {
            var suspendGr = new GlideRecord('x_2097092_linq_college');
            suspendGr.setLimit(1);
            if (suspendGr.get(input.college_id)) {
                suspendGr.setValue('status', 'suspended');
                suspendGr.update();
                data.successMsg = 'College suspended.';
            } else {
                data.errorMsg = 'College not found.';
            }
        }

        // Handle reject action
        if (input && input.action === 'reject') {
            var rejectGr = new GlideRecord('x_2097092_linq_college');
            rejectGr.setLimit(1);
            if (rejectGr.get(input.college_id)) {
                rejectGr.setValue('status', 'rejected');
                rejectGr.update();
                data.successMsg = 'College rejected.';
            } else {
                data.errorMsg = 'College not found.';
            }
        }

        // Load colleges (with optional filter)
        var filterStatus = '';
        if (input && input.action === 'filter' && input.filter_status && input.filter_status !== 'all') {
            filterStatus = input.filter_status;
        }

        var collegeGr = new GlideRecord('x_2097092_linq_college');
        if (filterStatus) {
            collegeGr.addQuery('status', filterStatus);
        }
        collegeGr.orderBy('name');
        collegeGr.setLimit(200);
        collegeGr.query();

        while (collegeGr.next()) {
            var collegeId = collegeGr.getUniqueValue();

            // Count clubs for this college
            var clubGa = new GlideAggregate('x_2097092_linq_club');
            clubGa.addQuery('college', collegeId);
            clubGa.addAggregate('COUNT');
            clubGa.query();
            var clubCount = 0;
            if (clubGa.next()) {
                clubCount = parseInt(clubGa.getAggregate('COUNT'), 10) || 0;
            }

            // Count events for this college
            var eventGa = new GlideAggregate('x_2097092_linq_event');
            eventGa.addQuery('college', collegeId);
            eventGa.addAggregate('COUNT');
            eventGa.query();
            var eventCount = 0;
            if (eventGa.next()) {
                eventCount = parseInt(eventGa.getAggregate('COUNT'), 10) || 0;
            }

            data.colleges.push({
                sys_id: collegeId,
                name: collegeGr.getValue('name') + '',
                code: collegeGr.getValue('code') + '',
                email_domain: collegeGr.getValue('email_domain') + '',
                status: collegeGr.getValue('status') + '',
                website: collegeGr.getValue('website') + '',
                clubs_count: clubCount,
                events_count: eventCount
            });
        }
    } catch (e) {
        gs.error('linq-admin-manage-colleges error: ' + e.message);
        data.errorMsg = 'An error occurred loading college data.';
    }
})();
